In case it helps anyone, I implemented a simple bcolz target:

```
from luigi.file import LocalFileSystem
import os
import pandas as pd
import bcolz
import luigi	

class bcolzTarget(luigi.Target):
	fs = LocalFileSystem()

	def __init__(self, path=None):
		self.path = path

	def exists(self):
		return self.fs.exists(self.path)

	def read(self, **kwargs):
		"""
		Opens bcolz ctable/carray in read-only mode.
		"""
		if self.exists():
			data = bcolz.open(self.path, mode='r', **kwargs)

			return data

	def write(self, data, **kwargs):
		"""
		Write a dataframe or bcolz ctable/carray to the specified
		filepath.
		"""
		self.makedirs()

		if isinstance(data, pd.DataFrame):
			bcolz.ctable.fromdataframe(data, rootdir=self.path)

		elif isinstance(data, (bcolz.ctable, bcolz.carray)):
			data.copy(rootdir=self.path)

		else:
			raise ValueError("Cannot convert type %s to bcolz" % type(data))

	def makedirs(self):
		"""
		Create all parent folders if they do not exist.
		"""
		normpath = os.path.normpath(self.path)
		parentfolder = os.path.dirname(normpath)
		if parentfolder:
			try:
				os.makedirs(parentfolder)
			except OSError:
				pass
```

