@Nopik , some possible optimization on your existing code:
When `UpdateServiceAlocs()`,  `GetNextService()` could be used to retrieve the service config of this device from existing leader network data,  thus only filling necessary Alocs instead of filling all Service Alocs.

Another suggestion is maybe a macro could be defined for the number of different services one device could support in src/core/openthread-core-default-config.h. As adding (kAloc16ServiceEnd - kAloc16ServiceStart) Service Alocs would mean additional 600+ Bytes are required. Some limited-resource platforms may not bear this.

I think your simplifications in the above are hiding something that is the real cause. I just pasted the following into a local app:

```
import factory
from django.db import models

class Verdict(models.Model):
    pass
class CaseType(models.Model):
    pass
class Session(models.Model):
    pass
class Role(models.Model):
    pass
class Village(models.Model):
    pass

class Person(models.Model):
    name = models.CharField(max_length=250)
    village = models.ForeignKey(Village)
    case_roles = models.ManyToManyField(Role, through="Litigant", related_name="case_roles")

class Case(models.Model):
    summary = models.TextField()
    session = models.ForeignKey(Session)
    case_type = models.ForeignKey(CaseType)
    verdict = models.ForeignKey(Verdict)
    litigants = models.ManyToManyField(Person, through="Litigant", related_name="litigants")

class Litigant(models.Model):
    person = models.ForeignKey(Person, on_delete=models.CASCADE)
    case = models.ForeignKey(Case, on_delete=models.CASCADE)
    role = models.ForeignKey(Role)
    notes = models.TextField()



class VillageFactory(factory.DjangoModelFactory):
    class Meta:
        model = Village
class SessionFactory(factory.DjangoModelFactory):
    class Meta:
        model = Session
class CaseTypeFactory(factory.DjangoModelFactory):
    class Meta:
        model = CaseType
class VerdictFactory(factory.DjangoModelFactory):
    class Meta:
        model = Verdict
class RoleFactory(factory.DjangoModelFactory):
    class Meta:
        model = Role

class CaseFactory(factory.DjangoModelFactory):
    class Meta:
        model = Case

    summary = factory.Faker('paragraph')
    session = factory.SubFactory(SessionFactory)
    case_type = factory.SubFactory(CaseTypeFactory)
    verdict = factory.SubFactory(VerdictFactory)


class PersonFactory(factory.DjangoModelFactory):
    class Meta:
        model = Person

    name = factory.Faker('first_name')
    village = factory.SubFactory(VillageFactory)
    notes = factory.Faker('paragraph')


class LitigantFactory(factory.DjangoModelFactory):
    class Meta:
        model = Litigant

    person = factory.SubFactory(PersonFactory)
    case = factory.SubFactory(CaseFactory)
    role = factory.SubFactory(RoleFactory)
    notes = factory.Faker('paragraph')
```

